content.css:
.pivot-wireframe,
.pivot-wireframe * {
  box-sizing: border-box;
}
.pivot-wireframe {
  width: 100%;
  height: 100%;
  min-width: 0;
  overflow: hidden;
  background: #f5f7fa;
  color: #142033;
  font-family: "Segoe UI", Arial, sans-serif;
  font-size: 14px;
}
.pivot-shell {
  display: flex;
  flex-direction: column;
  width: 100%;
  height: 100%;
}
.pivot-header {
  display: flex;
  align-items: center;
  min-height: 90px;
  padding: 18px 24px;
  background: #ffffff;
  border-bottom: 1px solid #e1e6ee;
}
.pivot-header-left {
  display: flex;
  align-items: center;
  min-width: 0;
  gap: 14px;
}
.pivot-logo {
  display: grid;
  place-items: center;
  width: 42px;
  height: 42px;
  flex: 0 0 42px;
  border: 1px solid #cfd8e6;
  border-radius: 8px;
  background: #f6f8fb;
  color: #47576d;
  font-size: 24px;
}
.pivot-header-copy {
  min-width: 0;
}
.pivot-title-line {
  display: flex;
  align-items: center;
  gap: 9px;
}
.pivot-title {
  margin: 0;
  font-size: 21px;
  font-weight: 700;
  line-height: 1.2;
}
.pivot-badge {
  padding: 4px 9px;
  border-radius: 12px;
  background: #edf1f7;
  color: #506078;
  font-size: 11px;
  font-weight: 600;
}
.pivot-subtitle {
  margin: 5px 0 0;
  color: #6d7888;
  font-size: 13px;
}
.pivot-header-actions {
  display: flex;
  gap: 7px;
}
.pivot-workspace {
  display: grid;
  grid-template-columns: minmax(0, 1fr) 290px;
  min-height: 0;
  flex: 1;
  gap: 18px;
  padding: 18px;
  overflow: hidden;
}
.pivot-main {
  display: flex;
  flex-direction: column;
  min-width: 0;
  min-height: 0;
  gap: 17px;
}
.pivot-card,
.pivot-fields-panel {
  background: #ffffff;
  border: 1px solid #e0e5ec;
  border-radius: 9px;
  box-shadow: 0 1px 2px rgba(0, 0, 0, 0.03), 0 4px 12px rgba(0, 0, 0, 0.025);
}
.pivot-builder {
  flex: 0 0 auto;
  padding: 16px;
}
.pivot-instruction {
  margin-bottom: 13px;
  color: #647084;
  font-size: 13px;
}
.pivot-wells {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  overflow: hidden;
  border: 1px solid #dfe5ed;
  border-radius: 8px;
}
.pivot-well {
  min-width: 0;
  padding: 14px;
  border-right: 1px solid #dfe5ed;
}
.pivot-well:last-child {
  border-right: 0;
}
.pivot-well-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 12px;
}
.pivot-well-heading {
  display: flex;
  align-items: center;
  min-width: 0;
  gap: 8px;
}
.pivot-well-icon {
  color: #667487;
  font-size: 17px;
}
.pivot-well-title {
  font-size: 13px;
  font-weight: 600;
}
.pivot-chevron {
  color: #778397;
  font-size: 14px;
}
.pivot-drop-zone {
  display: flex;
  align-items: center;
  min-height: 45px;
  min-width: 0;
  padding: 5px;
  border: 1px dashed #cdd5df;
  border-radius: 7px;
  background: #fafbfc;
}
.pivot-chip {
  display: flex;
  align-items: center;
  justify-content: space-between;
  width: 100%;
  min-width: 0;
  height: 34px;
  padding: 0 10px;
  border-radius: 6px;
}
.pivot-chip-blue {
  background: #eaf2ff;
  color: #1664c8;
}
.pivot-chip-green {
  background: #e8f5eb;
  color: #267647;
}
.pivot-chip-label {
  min-width: 0;
  overflow: hidden;
  font-size: 12px;
  font-weight: 500;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.pivot-chip-remove {
  margin-left: 8px;
  font-size: 17px;
}
.pivot-placeholder {
  width: 100%;
  color: #8b95a5;
  font-size: 12px;
  text-align: center;
}
.pivot-results {
  display: flex;
  flex-direction: column;
  min-height: 0;
  flex: 1;
  overflow: hidden;
}
.pivot-toolbar {
  display: flex;
  justify-content: flex-end;
  min-height: 54px;
  padding: 9px 13px;
  border-bottom: 1px solid #e0e5ec;
}
.pivot-toolbar-right {
  display: flex;
  align-items: center;
  gap: 6px;
}
.pivot-view-button {
  border: 1px solid #d8dee7;
  border-radius: 0;
}
.pivot-view-button:first-child {
  border-radius: 6px 0 0 6px;
}
.pivot-view-button:nth-child(2) {
  margin-left: -7px;
  border-radius: 0 6px 6px 0;
}
.pivot-view-button.active {
  background: #edf4ff;
  color: #1769d8;
}
.pivot-table-wrapper {
  min-width: 0;
  min-height: 0;
  flex: 1;
  padding: 13px;
  overflow: auto;
}
.pivot-table {
  min-width: 760px;
  overflow: hidden;
  border: 1px solid #dce2ea;
  border-radius: 7px;
}
.pivot-table-row {
  display: grid;
  grid-template-columns: 210px repeat(5, minmax(110px, 1fr));
}
.pivot-top-header {
  grid-template-columns: 210px minmax(550px, 5fr);
}
.pivot-category-header {
  grid-template-columns: 210px minmax(550px, 5fr);
}
.pivot-cell {
  display: flex;
  align-items: center;
  min-height: 52px;
  padding: 10px 13px;
  border-right: 1px solid #e1e6ed;
  border-bottom: 1px solid #e1e6ed;
  background: #ffffff;
  font-size: 12px;
}
.pivot-cell:last-child {
  border-right: 0;
}
.pivot-table-row:last-child .pivot-cell {
  border-bottom: 0;
}
.pivot-top-header .pivot-cell,
.pivot-year-header .pivot-cell,
.pivot-category-header .pivot-cell {
  background: #fafbfd;
  font-weight: 600;
}
.pivot-column-header {
  justify-content: flex-start;
}
.pivot-row-header {
  font-weight: 600;
}
.numeric {
  justify-content: flex-end;
  font-variant-numeric: tabular-nums;
}
.total-cell {
  background: #fafbfd;
  font-weight: 700;
}
.grand-total .pivot-cell {
  background: #f6f8fb;
  font-weight: 700;
}
.pivot-footer {
  display: flex;
  align-items: center;
  min-height: 53px;
  gap: 8px;
  padding: 0 16px;
  border-top: 1px solid #e0e5ec;
  color: #69768a;
}
.pivot-footer-text {
  font-size: 11px;
}
.pivot-fields-panel {
  display: flex;
  flex-direction: column;
  min-width: 0;
  min-height: 0;
  overflow: hidden;
}
.pivot-fields-title {
  margin: 0;
  padding: 17px 17px 11px;
  font-size: 16px;
}
.pivot-search {
  display: flex;
  align-items: center;
  min-height: 40px;
  margin: 0 17px 10px;
  gap: 8px;
  padding: 0 10px;
  border: 1px solid #d6dde7;
  border-radius: 7px;
  color: #8590a1;
}
.pivot-search-icon {
  font-size: 19px;
}
.pivot-search-placeholder {
  font-size: 12px;
}
.pivot-field-list {
  min-height: 0;
  flex: 1;
  padding: 0 17px;
  overflow-y: auto;
}
.pivot-field-group {
  padding: 8px 0 10px;
  border-bottom: 1px solid #e4e8ee;
}
.pivot-field-group-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  min-height: 32px;
}
.pivot-field-group-heading {
  display: flex;
  align-items: center;
  gap: 8px;
}
.pivot-field-group-title {
  font-size: 12px;
  font-weight: 600;
}
.pivot-field-group-chevron {
  color: #748094;
}
.pivot-field-group-body {
  display: flex;
  flex-direction: column;
}
.pivot-field-item {
  display: grid;
  grid-template-columns: 17px 23px minmax(0, 1fr);
  align-items: center;
  min-height: 32px;
  gap: 7px;
  border-radius: 5px;
}
.pivot-field-item:hover {
  background: #f5f7fa;
}
.pivot-checkbox {
  display: grid;
  place-items: center;
  width: 16px;
  height: 16px;
  border: 1px solid #aeb8c5;
  border-radius: 3px;
  color: white;
  font-size: 10px;
}
.pivot-checkbox.selected {
  border-color: #1769d8;
  background: #1769d8;
}
.pivot-field-type {
  color: #738095;
  font-size: 10px;
}
.pivot-field-name {
  min-width: 0;
  overflow: hidden;
  color: #344155;
  font-size: 12px;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.pivot-help {
  display: flex;
  align-items: flex-start;
  min-height: 78px;
  gap: 8px;
  padding: 14px 17px;
  border-top: 1px solid #dfe5ec;
  background: #f3f7ff;
  color: #245fae;
}
.pivot-help-text {
  font-size: 11px;
  line-height: 1.45;
}
.pivot-wireframe.compact .pivot-workspace {
  grid-template-columns: minmax(0, 1fr) 240px;
  gap: 11px;
  padding: 11px;
}
.pivot-wireframe.compact .pivot-wells {
  grid-template-columns: repeat(2, minmax(0, 1fr));
}
.pivot-wireframe.compact .pivot-well:nth-child(2) {
  border-right: 0;
}
.pivot-wireframe.compact .pivot-well:nth-child(-n + 2) {
  border-bottom: 1px solid #dfe5ed;
}
.pivot-wireframe.narrow .pivot-workspace {
  display: flex;
  flex-direction: column;
  overflow-y: auto;
}
.pivot-wireframe.narrow .pivot-header-actions {
  display: none;
}
.pivot-wireframe.narrow .pivot-subtitle {
  display: none;
}
.pivot-wireframe.narrow .pivot-wells {
  grid-template-columns: 1fr;
}
.pivot-wireframe.narrow .pivot-well {
  border-right: 0;
  border-bottom: 1px solid #dfe5ed;
}
.pivot-wireframe.narrow .pivot-fields-panel {
  min-height: 400px;
}
.pivot-field-checkbox-input {
  position: absolute;
  width: 1px;
  height: 1px;
  overflow: hidden;
  opacity: 0;
  pointer-events: none;
}
.pivot-fields-empty {
  padding: 24px 12px;
  color: #7b8798;
  font-size: 12px;
  line-height: 1.5;
  text-align: center;
}
.pivot-search {
  width: calc(100% - 34px);
  min-height: 40px;
  margin: 0 17px 10px;
  padding: 0 12px;
  border: 1px solid #d6dde7;
  border-radius: 7px;
  background: #ffffff;
  color: #344155;
  font-family: inherit;
  font-size: 12px;
  outline: none;
}
.pivot-search:focus {
  border-color: #1769d8;
  box-shadow: 0 0 0 2px rgba(23, 105, 216, 0.12);
}
